export class PgEmployeeRepository extends BaseRepository<Employee> implements IEmployeeRepository {
  constructor(pool: Pool) {
    super(pool, 'employees');
  }

  async findByEmail(email: string, client?: PoolClient): Promise<Employee | null> {
    const query = 'SELECT * FROM employees WHERE email = $1 AND deleted_at IS NULL';
    const result = await this.executeQuery(query, [email], client);
    return this.mapRow(result.rows[0]);
  }

  async findByEmployeeNumber(employeeNumber: string, client?: PoolClient): Promise<Employee | null> {
    const query = 'SELECT * FROM employees WHERE employee_number = $1 AND deleted_at IS NULL';
    const result = await this.executeQuery(query, [employeeNumber], client);
    return this.mapRow(result.rows[0]);
  }

  async findByManagerId(managerId: string, client?: PoolClient): Promise<Employee[]> {
    const query = 'SELECT * FROM employees WHERE manager_id = $1 AND deleted_at IS NULL';
    const result = await this.executeQuery(query, [managerId], client);
    return result.rows.map(row => this.mapRow(row));
  }

  async findActive(client?: PoolClient): Promise<Employee[]> {
    const query = 'SELECT * FROM employees WHERE employment_status = $1 AND deleted_at IS NULL';
    const result = await this.executeQuery(query, ['ACTIVE'], client);
    return result.rows.map(row => this.mapRow(row));
  }

  async list(filters?: EmployeeFilters, client?: PoolClient): Promise<Employee[]> {
    let query = 'SELECT * FROM employees WHERE deleted_at IS NULL';
    const params: any[] = [];
    if (filters?.department) {
      params.push(filters.department);
      query += ` AND department = $${params.length}`;
    }
    if (filters?.employmentStatus) {
      params.push(filters.employmentStatus);
      query += ` AND employment_status = $${params.length}`;
    }
    if (filters?.managerId) {
      params.push(filters.managerId);
      query += ` AND manager_id = $${params.length}`;
    }
    if (filters?.search) {
      params.push(`%${filters.search}%`);
      query += ` AND (first_name ILIKE $${params.length} OR last_name ILIKE $${params.length} OR employee_number ILIKE $${params.length})`;
    }
    if (filters?.limit) {
      params.push(filters.limit);
      query += ` LIMIT $${params.length}`;
    }
    if (filters?.offset) {
      params.push(filters.offset);
      query += ` OFFSET $${params.length}`;
    }
    const result = await this.executeQuery(query, params, client);
    return result.rows.map(row => this.mapRow(row));
  }

  protected mapRow(row: any): Employee {
    if (!row) return null;
    return {
      id: row.id,
      employeeNumber: row.employee_number,
      firstName: row.first_name,
      lastName: row.last_name,
      email: row.email,
      managerId: row.manager_id,
      department: row.department,
      hireDate: row.hire_date,
      terminationDate: row.termination_date,
      employmentStatus: row.employment_status,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
      deletedAt: row.deleted_at,
    };
  }
